SELECT COUNT(*)
FROM pt_private_appointment
WHERE coach_id = #{coachId}
  AND appointment_date = #{appointmentDate}
  AND start_time < #{endTime}
  AND end_time > #{startTime}
  AND appointment_status IN (1, 3, 4)
  AND deleted = 0

SELECT COUNT(*)
FROM pt_private_appointment
WHERE member_id = #{memberId}
  AND appointment_date = #{appointmentDate}
  AND start_time < #{endTime}
  AND end_time > #{startTime}
  AND appointment_status = 1
  AND deleted = 0

mapper.update:
UPDATE pt_private_appointment
SET appointment_status = 3, finish_at = NOW(), updated_by = #{operatorId}
WHERE id = #{id} AND appointment_status = 1

mapper.select:
SELECT a.id, a.appointment_no, a.order_id, a.benefit_id, a.member_id, a.product_id, a.coach_id, a.store_id, DATE_FORMAT(a.appointment_date, '%Y-%m-%d') AS appointmentDate, DATE_FORMAT(a.start_time, '%H:%i') AS startTime, DATE_FORMAT(a.end_time, '%H:%i') AS endTime, a.lesson_count, a.appointment_status, a.cancel_reason, a.cancel_at, a.finish_at, a.created_at, p.product_name AS productName, c.coach_name AS coachName, s.storeName AS storeName FROM pt_private_appointment a LEFT JOIN pt_product p ON p.id = a.product_id LEFT JOIN pt_coach c ON c.id = a.coach_id LEFT JOIN store s ON s.storeId = a.store_id WHERE a.member_id = #{userId} AND a.deleted = 0
AND a.appointment_status = #{status}
ORDER BY a.appointment_date DESC, a.start_time DESC, a.id DESC
LIMIT #{offset}, #{limit}

SELECT sch.store_id AS storeId, DATE_FORMAT(sch.start_time, '%H:%i') AS startTime, DATE_FORMAT(sch.end_time, '%H:%i') AS endTime FROM pt_coach_schedule sch INNER JOIN pt_coach c ON c.id = sch.coach_id AND c.status = 1 AND c.deleted = 0 INNER JOIN pt_coach_store_rel csr ON csr.coach_id = sch.coach_id AND csr.store_id = sch.store_id WHERE sch.coach_id = #{coachId} AND sch.weekday = #{weekday} AND sch.is_enabled = 1 AND sch.store_id IN (SELECT store_id FROM pt_product_store_rel WHERE product_id = #{productId}) AND ( NOT EXISTS (SELECT 1 FROM pt_product_coach_rel WHERE product_id = #{productId}) OR sch.coach_id IN (SELECT coach_id FROM pt_product_coach_rel WHERE product_id = #{productId}) )
AND sch.store_id = #{storeId}
ORDER BY sch.store_id ASC, sch.start_time ASC

SELECT COUNT(*)
FROM pt_private_appointment
WHERE coach_id = #{coachId}
  AND store_id = #{storeId}
  AND appointment_status = 1
  AND deleted = 0
  AND WEEKDAY(appointment_date) + 1 = #{weekday}
  AND start_time >= #{startTime}
  AND end_time <= #{endTime}
  AND TIMESTAMP(appointment_date, start_time) > NOW()
